 {"id":"gt-8tmz.20","title":"Formula inheritance trees for organizational policies","description":"Support organizational formula hierarchies where teams extend a company-base-formula. Each team can add required aspects (accessibility audit for frontend, SQL injection scan for backend). Enables policy enforcement across an organization.","status":"open","priority":3,"issue_type":"feature","created_at":"2025-12-23T18:45:46.888965-08:00","updated_at":"2025-12-23T18:45:46.888965-08:00","dependencies":[{"issue_id":"gt-8tmz.20","depends_on_id":"gt-8tmz","type":"parent-child","created_at":"2025-12-23T18:45:46.889387-08:00","created_by":"daemon"}]}
